pub async fn save(self) -> Result<FailedJobView> {
        let __create_input = if try_get_observer().is_some() {
            Some(self.to_create_input()?)
        } else {
            None
        };
        if let Some(observer) = try_get_observer() {
            if let Some(create_input) = __create_input.as_ref() {
                let event = ModelEvent { model: "failed_job", table: "failed_jobs", record_key: None };
                let data = serde_json::to_value(create_input)?;
                observer.on_creating(&event, &data).await?;
            }
        }
        let db_conn = self.db.clone();
        match db_conn {
            DbConn::Pool(pool) => {
                let tx = pool.begin().await?;
                let tx_lock = std::sync::Arc::new(tokio::sync::Mutex::new(tx));
                let (view, row) = {
                    let db = DbConn::tx(tx_lock.clone());
                    self.save_with_db(db).await?
                };
                let tx = std::sync::Arc::try_unwrap(tx_lock)
                    .map_err(|_| anyhow::anyhow!("transaction scope still has active handles"))?
                    .into_inner();
                tx.commit().await?;
                if let Some(observer) = try_get_observer() {
                    let event = ModelEvent { model: "failed_job", table: "failed_jobs", record_key: Some(format!("{}", row.id)) };
                    match serde_json::to_value(&row) {
                        Ok(data) => {
                            if let Err(err) = observer.on_created(&event, &data).await {
                                log_observer_error("created", "failed_job", &err);
                            }
                        }
                        Err(err) => log_observer_error("created", "failed_job", &err),
                    }
                }
                Ok(view)
            }
            DbConn::Tx(_) => {
                let (view, row) = self.save_with_db(db_conn).await?;
                if let Some(observer) = try_get_observer() {
                    let event = ModelEvent { model: "failed_job", table: "failed_jobs", record_key: Some(format!("{}", row.id)) };
                    match serde_json::to_value(&row) {
                        Ok(data) => {
                            if let Err(err) = observer.on_created(&event, &data).await {
                                log_observer_error("created", "failed_job", &err);
                            }
                        }
                        Err(err) => log_observer_error("created", "failed_job", &err),
                    }
                }
                Ok(view)
            }
        }
    }

    async fn save_with_db<'tx>(self, db: DbConn<'tx>) -> Result<(FailedJobView, FailedJobRow)> {
        let mut cols = self.cols;
        let mut binds = self.binds;
        if cols.is_empty() {
            anyhow::bail!("insert: no columns set");
        }
        let col_sql: Vec<&'static str> = cols.iter().map(|c| c.as_sql()).collect();
        let placeholders: Vec<String> = (1..=binds.len()).map(|i| format!("${}", i)).collect();
        let mut sql = format!("INSERT INTO {} ({}) VALUES ({})", "failed_jobs", col_sql.join(", "), placeholders.join(", "));
        if let Some(action) = self.conflict_action {
            if !self.conflict_cols.is_empty() {
                let conflict_col_sql: Vec<&'static str> = self.conflict_cols.iter().map(|c| c.as_sql()).collect();
                sql.push_str(&format!(" ON CONFLICT ({}) {}", conflict_col_sql.join(", "), action));
                if action == "DO UPDATE" {
                    let set_clauses: Vec<String> = col_sql.iter().zip(placeholders.iter())
                        .filter(|(col, _)| !conflict_col_sql.contains(col))
                        .map(|(col, ph)| format!("{} = {}", col, ph))
                        .collect();
                    if !set_clauses.is_empty() {
                        sql.push_str(&format!(" SET {}", set_clauses.join(", ")));
                    }
                }
            }
        }
        sql.push_str(" RETURNING *");
        let __profiler_binds = if is_sql_profiler_enabled() { binds.iter().map(|b| format!("{}", b)).collect::<Vec<_>>().join(", ") } else { String::new() };
        let __profiler_start = std::time::Instant::now();
        let mut q = sqlx::query_as::<_, FailedJobRow>(&sql);
        for b in binds {
            q = bind(q, b);
        }
        let row = db.fetch_one(q).await?;
        record_profiled_query("failed_jobs", "INSERT", &sql, &__profiler_binds, __profiler_start.elapsed());
        let localized = LocalizedMap::default();
        let view = hydrate_view(row.clone(), &LocalizedMap::default(), self.base_url.as_deref());
        Ok((view, row))
    }
